export function streamOpenAIToAnthropic(
  openaiStream: ReadableStream,
  model: string,
  abortSignal?: AbortSignal,
): ReadableStream {
  const messageId = "msg_" + Date.now();
  let streamCancelled = false;

  const enqueueSSE = (controller: ReadableStreamDefaultController, eventType: string, data: any) => {
    if (streamCancelled) return;
    try {
      const sseMessage = `event: ${eventType}\ndata: ${JSON.stringify(data)}\n\n`;
      controller.enqueue(new TextEncoder().encode(sseMessage));
    } catch (e) {
      // Controller might already be closed/errored - ignore
    }
  };
  
  return new ReadableStream({
    async start(controller) {
      // Send message_start event
      const messageStart = {
        type: "message_start",
        message: {
          id: messageId,
          type: "message",
          role: "assistant",
          content: [],
          model,
          stop_reason: null,
          stop_sequence: null,
          usage: { input_tokens: 0, output_tokens: 0 },
        },
      };
      enqueueSSE(controller, "message_start", messageStart);

      let contentBlockIndex = 0;
      let hasStartedTextBlock = false;
      let hasStartedThinkingBlock = false;
      let isToolUse = false;
      let currentToolCallId: string | null = null;
      let toolCallJsonMap = new Map<string, string>();
      let usage: { prompt_tokens?: number; completion_tokens?: number } | undefined = undefined;

      const reader = openaiStream.getReader();
      const decoder = new TextDecoder();
      let buffer = '';

      // Listen to abort signal to cancel the stream reading
      if (abortSignal) {
        abortSignal.addEventListener('abort', () => {
          streamCancelled = true;
          try { reader.cancel(); } catch (_) { /* ignore */ }
          try { controller.close(); } catch (_) { /* ignore */ }
        }, { once: true });
      }

      try {
        while (!streamCancelled) {
          let result: ReadableStreamReadResult<Uint8Array>;
          try {
            result = await reader.read();
          } catch (readErr: any) {
            console.error('stream read error:', readErr?.message || readErr);
            break;
          }

          const { done, value } = result;
          if (done) {
            // Process any remaining data in buffer
            if (buffer.trim()) {
              const lines = buffer.split('\n');
              for (const line of lines) {
                if (line.trim() && line.startsWith('data: ')) {
                  const data = line.slice(6).trim();
                  if (data === '[DONE]') continue;
                  
                  try {
                    const parsed = JSON.parse(data);
                    if (parsed.usage) {
                      usage = parsed.usage;
                    }
                    const delta = parsed.choices?.[0]?.delta;
                    if (delta) {
                      processStreamDelta(delta);
                    }
                  } catch (e) {
                    // Parse error - skip malformed line
                  }
                }
              }
            }
            break;
          }
          
          // Decode chunk and add to buffer
          let chunk: string;
          try {
            chunk = decoder.decode(value, { stream: true });
          } catch (decodeErr: any) {
            console.error('stream decode error:', decodeErr?.message || decodeErr);
            continue;
          }
          buffer += chunk;
          
          // Process complete lines from buffer
          const lines = buffer.split('\n');
          // Keep the last potentially incomplete line in buffer
          buffer = lines.pop() || '';
          
          // Process complete lines in order
          for (const line of lines) {
            if (line.trim() && line.startsWith('data: ')) {
              const data = line.slice(6).trim();
              if (data === '[DONE]') continue;
              
              try {
                const parsed = JSON.parse(data);
                if (parsed.usage) {
                  usage = parsed.usage;
                }
                const delta = parsed.choices?.[0]?.delta;
                
                if (delta) {
                  processStreamDelta(delta);
                }
              } catch (e) {
                // Parse error - skip malformed line
                continue;
              }
            }
          }
        }
      } catch (outerErr: any) {
        console.error('stream processing outer error:', outerErr?.message || outerErr);
        streamCancelled = true;
      } finally {
        try {
          reader.releaseLock();
        } catch (_) { /* ignore */ }
      }

      function processStreamDelta(delta: any) {
        if (streamCancelled) return;

        // Handle tool calls
        if (delta.tool_calls?.length > 0) {
          for (const toolCall of delta.tool_calls) {
            const toolCallId = toolCall.id;

            if (toolCallId && toolCallId !== currentToolCallId) {
              if (isToolUse || hasStartedTextBlock || hasStartedThinkingBlock) {
                enqueueSSE(controller, "content_block_stop", {
                  type: "content_block_stop",
                  index: contentBlockIndex,
                });
              }

              isToolUse = true;
              hasStartedTextBlock = false;
              hasStartedThinkingBlock = false;
              currentToolCallId = toolCallId;
              contentBlockIndex++;
              toolCallJsonMap.set(toolCallId, "");

              const toolBlock = {
                type: "tool_use",
                id: toolCallId,
                name: toolCall.function?.name,
                input: {},
              };

              enqueueSSE(controller, "content_block_start", {
                type: "content_block_start",
                index: contentBlockIndex,
                content_block: toolBlock,
              });
            }

            if (toolCall.function?.arguments && currentToolCallId) {
              const currentJson = toolCallJsonMap.get(currentToolCallId) || "";
              toolCallJsonMap.set(currentToolCallId, currentJson + toolCall.function.arguments);

              enqueueSSE(controller, "content_block_delta", {
                type: "content_block_delta",
                index: contentBlockIndex,
                delta: {
                  type: "input_json_delta",
                  partial_json: toolCall.function.arguments,
                },
              });
            }
          }
        } else if (delta.reasoning) {
          // Handle reasoning/thinking
          if (isToolUse || hasStartedTextBlock) {
            enqueueSSE(controller, "content_block_stop", {
              type: "content_block_stop",
              index: contentBlockIndex,
            });
            isToolUse = false;
            hasStartedTextBlock = false;
            currentToolCallId = null;
            contentBlockIndex++;
          }

          if (!hasStartedThinkingBlock) {
            enqueueSSE(controller, "content_block_start", {
              type: "content_block_start",
              index: contentBlockIndex,
              content_block: {
                type: "thinking",
                thinking: "",
                signature: "openrouter-reasoning"
              },
            });
            hasStartedThinkingBlock = true;
          }

          enqueueSSE(controller, "content_block_delta", {
            type: "content_block_delta",
            index: contentBlockIndex,
            delta: {
              type: "thinking_delta",
              thinking: delta.reasoning,
            },
          });

        } else if (delta.content) {
          if (isToolUse || hasStartedThinkingBlock) {
            enqueueSSE(controller, "content_block_stop", {
              type: "content_block_stop",
              index: contentBlockIndex,
            });
            isToolUse = false;
            hasStartedThinkingBlock = false;
            currentToolCallId = null;
            contentBlockIndex++;
          }

          if (!hasStartedTextBlock) {
            enqueueSSE(controller, "content_block_start", {
              type: "content_block_start",
              index: contentBlockIndex,
              content_block: {
                type: "text",
                text: "",
              },
            });
            hasStartedTextBlock = true;
          }

          enqueueSSE(controller, "content_block_delta", {
            type: "content_block_delta",
            index: contentBlockIndex,
            delta: {
              type: "text_delta",
              text: delta.content,
            },
          });
        }
      }

      // Only send closing events if we didn't cancel mid-stream
      if (!streamCancelled) {
        // Close last content block
        if (isToolUse || hasStartedTextBlock || hasStartedThinkingBlock) {
          enqueueSSE(controller, "content_block_stop", {
            type: "content_block_stop",
            index: contentBlockIndex,
          });
        }

        // Send message_delta and message_stop
        enqueueSSE(controller, "message_delta", {
          type: "message_delta",
          delta: {
            stop_reason: isToolUse ? "tool_use" : "end_turn",
            stop_sequence: null,
          },
          usage: {
            input_tokens: usage?.prompt_tokens || 0,
            output_tokens: usage?.completion_tokens || 0,
          },
        });

        enqueueSSE(controller, "message_stop", {
          type: "message_stop",
        });
      }

      try {
        controller.close();
      } catch (_) { /* ignore if already closed */ }
    },

    cancel(reason) {
      streamCancelled = true;
      console.error('stream cancelled by consumer:', reason);
    },
  });
}